212	        /// Read data from the fifo into `dst`, returns number of items copied.
213	        pub fn read(self: *Self, dst: []T) usize {
214	            var dst_left = dst;
215	
216	            while (dst_left.len > 0) {
217	                const slice = self.readableSlice(0);
218	                if (slice.len == 0) break;
219	                const n = @min(slice.len, dst_left.len);
220	                bun.copy(T, dst_left, slice[0..n]);
221	                self.discard(n);
