331	        /// Make `count` items available before the current read location
332	        fn rewind(self: *Self, count: usize) void {
333	            assert(self.writableLength() >= count);
334	
335	            var head = self.head + (self.buf.len - count);
336	            if (powers_of_two) {
337	                head &= self.buf.len - 1;
338	            } else {
339	                head %= self.buf.len;
340	            }
341	            self.head = head;
342	            self.count += count;
