345	        /// Place data back into the read stream
346	        pub fn unget(self: *Self, src: []const T) !void {
347	            try self.ensureUnusedCapacity(src.len);
348	
349	            self.rewind(src.len);
350	
351	            const slice = self.readableSliceMut(0);
352	            if (src.len < slice.len) {
353	                bun.copy(T, slice, src);
354	            } else {
355	                bun.copy(T, slice, src[0..slice.len]);
356	                const slice2 = self.readableSliceMut(slice.len);
357	                bun.copy(T, slice2, src[slice.len..]);
