362	        /// Asserts offset is within bounds.
363	        pub fn peekItem(self: Self, offset: usize) T {
364	            assert(offset < self.count);
365	
366	            var index = self.head + offset;
367	            if (powers_of_two) {
368	                index &= self.buf.len - 1;
369	            } else {
