389	        /// Remove one item at `offset` and MOVE all items after it up one.
390	        pub fn orderedRemoveItem(self: *Self, offset: usize) void {
391	            if (offset == 0) return self.discard(1);
392	
393	            assert(offset < self.count);
394	
395	            if (self.buf.len - self.head >= self.count) {
396	                // If it doesnt overflow past the end, there is one copy to be done
397	                const rest = self.buf[self.head + offset ..];
398	                bun.copy(T, rest[0 .. rest.len - 1], rest[1..]);
399	            } else {
400	                var index = self.head + offset;
401	                if (powers_of_two) {
402	                    index &= self.buf.len - 1;
403	                } else {
404	                    index %= self.buf.len;
405	                }
406	                if (index < self.head) {
407	                    // If the item to remove is before the head, one slice is moved.
408	                    const rest = self.buf[index .. self.count - self.head];
409	                    bun.copy(T, rest[0 .. rest.len - 1], rest[1..]);
410	                } else {
411	                    // The items before and after the head have to be shifted
412	                    const wrap = self.buf[0];
413	                    const right = self.buf[index..];
414	                    bun.copy(T, right[0 .. right.len - 1], right[1..]);
415	                    self.buf[self.buf.len - 1] = wrap;
416	                    const left = self.buf[0 .. self.head - self.count];
417	                    bun.copy(T, left[0 .. left.len - 1], left[1..]);
418	                }
419	            }
420	            self.count -= 1;
421	        }
