423	        /// Pump data from a reader into a writer
424	        /// stops when reader returns 0 bytes (EOF)
425	        /// Buffer size must be set before calling; a buffer length of 0 is invalid.
426	        pub fn pump(self: *Self, src_reader: anytype, dest_writer: *std.Io.Writer) !void {
427	            assert(self.buf.len > 0);
428	            while (true) {
429	                if (self.writableLength() > 0) {
430	                    const n = try src_reader.read(self.writableSlice(0));
431	                    if (n == 0) break; // EOF
432	                    self.update(n);
433	                }
434	                self.discard(try dest_writer.write(self.readableSlice(0)));
435	            }
436	            // flush remaining data
437	            while (self.readableLength() > 0) {
438	                self.discard(try dest_writer.write(self.readableSlice(0)));
439	            }
440	        }
441	    };
